// SCALAR alias — use direct comparison
// Microsoft.KeyVault/vaults/enableSoftDelete is noneArray (boolean)
{
  "field": "Microsoft.KeyVault/vaults/enableSoftDelete",
  "equals": "true"
}

// ARRAY alias — use count expression
// Microsoft.Network/networkSecurityGroups/securityRules[*] is arrayExpression
{
  "count": {
    "field": "Microsoft.Network/networkSecurityGroups/securityRules[*]",
    "where": {
      "field": "Microsoft.Network/networkSecurityGroups/securityRules[*].access",
      "equals": "Allow"
    }
  },
  "greater": 0
}

// WRONG: do not compare array alias with equals directly
// This will never match as expected:
{
  "field": "Microsoft.Network/networkSecurityGroups/securityRules[*].access",
  "equals": "Allow"
  // WRONG — this alias is arrayMember, not usable at top-level
}

// value conditions for properties without aliases

// 1. Test the resource group's tag — no field alias for RG tags on child resources
{
  "value": "[resourceGroup().tags['CostCenter']]",
  "notEquals": ""
}

// 2. Test the subscription ID
{
  "value": "[subscription().subscriptionId]",
  "notIn": "[parameters('blockedSubscriptions')]"
}

// 3. Test the resource group name pattern
{
  "value": "[resourceGroup().name]",
  "like": "rg-prod-*"
}

// 4. Concatenate values for dynamic field references (parameter-driven tag name)
{
  "field": "[concat('tags[', parameters('tagName'), ']')]",
  "exists": "true"
}

// 5. Always-true condition (match all resources in a scope)
{
  "value": "true",
  "equals": "true"
}

// Modify: ensure a specific tag exists with a correct value
// The alias tags['Environment'] is modifiable on all resource types
{
  "if": {
    "allOf": [
      { "field": "type", "notIn": ["Microsoft.Resources/subscriptions", "Microsoft.Resources/subscriptions/resourceGroups"] },
      { "field": "tags['Environment']", "notIn": ["prod", "dev", "test", "staging"] }
    ]
  },
  "then": {
    "effect": "modify",
    "details": {
      "roleDefinitionIds": [
        "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
      ],
      "operations": [
        {
          "operation": "addOrReplace",
          "field": "tags['Environment']",
          "value": "[parameters('defaultEnvironmentTag')]"
        }
      ]
    }
  }
}

// Modify: add multiple tags without removing existing ones
{
  "then": {
    "effect": "modify",
    "details": {
      "roleDefinitionIds": [
        "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
      ],
      "operations": [
        { "operation": "add", "field": "tags['ManagedBy']", "value": "policy" },
        { "operation": "add", "field": "tags['CreatedDate']", "value": "[utcNow()]" }
      ]
    }
  }
}

// Modify: remove a deprecated tag
{
  "if": {
    "field": "tags['OldTagName']",
    "exists": "true"
  },
  "then": {
    "effect": "modify",
    "details": {
      "roleDefinitionIds": [
        "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
      ],
      "operations": [
        { "operation": "remove", "field": "tags['OldTagName']" }
      ]
    }
  }
}

// Using field() inside a DINE deployment to pass evaluated resource properties
// to the ARM template being deployed
{
  "then": {
    "effect": "deployIfNotExists",
    "details": {
      "deployment": {
        "properties": {
          "mode": "incremental",
          "parameters": {
            "vmName":     { "value": "[field('name')]" },
            "vmLocation": { "value": "[field('location')]" },
            "vmId":       { "value": "[field('id')]" },
            "osSku":      { "value": "[field('Microsoft.Compute/virtualMachines/storageProfile.osDisk.osType')]" }
          },
          "template": {
            "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
            "contentVersion": "1.0.0.0",
            "parameters": {
              "vmName":     { "type": "string" },
              "vmLocation": { "type": "string" },
              "vmId":       { "type": "string" },
              "osSku":      { "type": "string" }
            },
            "resources": [
              {
                "type": "Microsoft.Compute/virtualMachines/extensions",
                "name": "[concat(parameters('vmName'), '/AzureMonitorWindowsAgent')]",
                "location": "[parameters('vmLocation')]"
              }
            ]
          }
        }
      }
    }
  }
}
